head.script:
//-------------------------------------------------------------------------
// PGMл™Е : м£ЉмЬ†мЖМмИШмИШл£М/нХ†мЭЄлЛ®к∞АлУ±л°Э (tr_270_02_01b)
// мЮСмД±мЮР : мЖ°м†ХнЭђ
// мµЬміИмЮСмД±мЭЉмЮР : 2026-01-26
//-------------------------------------------------------------------------
scwin.fromDate_YMD = ""; // мЮСмЧЕлВ†мІЬ
scwin.fromDate_YMD = WebSquare.date.getCurrentServerDate("yyyyMMdd");
scwin.sort_options = {};
scwin.sort_options.sortIndex = "clntNo oilStatClsCd oilCoCd";
scwin.sort_options.sortOrder = "1 1 1";
scwin.sort_options1 = {};
scwin.sort_options1.sortIndex = "clntNo stdDt";
scwin.sort_options1.sortOrder = "1 0";
scwin.addRow = "";
scwin.pos_rowSts = 0;
scwin.uprBfVal = "";
scwin.stdDtBfVal = "";
scwin.updateStaus = "";
scwin.isClose = "";

//-------------------------------------------------------------------------
// нЩФл©і л°ЬлФ©мЛЬ
//-------------------------------------------------------------------------
scwin.onpageload = async function() {

    const codeOptions = [
        { grpCd: "ZZ503", compID: "gr_oilStation:oilStatClsCd" },        // м£ЉмЬ†мЖМкµђлґД
        { grpCd: "ZZ506", compID: "gr_oilStation:exprClntUprCond" } // лЛ®к∞Ам°∞к±і
    ];
    $c.data.setCommonCode(codeOptions); 

    const LxCodeOptions = [
        {
            method: "getLuxeComboData",
            param1: "PsCommonEBC",
            param2: "retriveOilStatClsCd",
            compID: "lc_oilStatDivision"
        }  // м£ЉмЬ†мЖМкµђлґД
    ];
    $c.data.setGauceUtil(LxCodeOptions);    

    await scwin.lc_oilStatClsCd_onchange();
};

//-------------------------------------------------------------------------
// м°∞нЪМм°∞к±і : м£ЉмЬ†мЖМкµђлґД мљ§л≥і м°∞нЪМ
//-------------------------------------------------------------------------
scwin.lc_oilStatClsCd_onchange = function (info) {
    scwin.f_RetrieveSecond(lc_oilStatDivision.getValue());
};

//-------------------------------------------------------------------------
// м°∞нЪМм°∞к±і : м£ЉмЬ†мЖМ мљ§л≥і м°∞нЪМ
//-------------------------------------------------------------------------
scwin.f_RetrieveSecond = async function (param1) {
	dma_lux_oilStation.set("cmd", "retriveOilStation");
    dma_lux_oilStation.set("strVal", param1);

    await $c.sbm.execute(sbm_lux_oilStation);    
};

scwin.sbm_lux_oilStation_submitdone = function (e) {
    if( ds_lux_oilStation.getRowCount() > 0 ) {
        ds_lux_oilStation.insertRow(1); 
        ds_lux_oilStation.setCellData(1, "code", "");
        ds_lux_oilStation.setCellData(1, "name", "м†Дм≤і");

        lc_oilStation.setSelectedIndex(0);
    }
};

//-------------------------------------------------------------------------
// м£ЉмЬ†мЖМл™©л°Э DataList : DataList л≥Ак≤љлРЬ к≤љмЪ∞ л∞ЬмГЭ мЭіл≤§нКЄ
//-------------------------------------------------------------------------
scwin.ds_oilStation_ondataload = function () {
    let rowCnt = ds_oilStation.getTotalRow();
    totalRows.setValue(rowCnt);    

    if( rowCnt == 0 ) {
	    if( $c.gus.cfCheckCreateFlag() == true){
	    	$c.gus.cfTurnCreateFlag(false);
	    }else{
	 		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
	    }
       return;
	} 

    if (rowCnt > 0) {        
        // ds_oilStation.multisort(scwin.sort_options);  
        gr_oilStation.setGridReadOnly(true);
    }    
};

//-------------------------------------------------------------------------
// м£ЉмЬ†мЖМл™©л°Э DataList : нЦЙмЭШ мЭЄлН±мК§ л≥Ак≤љлРЬ к≤љмЪ∞ л∞ЬмГЭ мЭіл≤§нКЄ
//-------------------------------------------------------------------------
scwin.ds_oilStation_onrowpositionchange = async function (info) {
    var rowIndex = info.newRowIndex;
    let chkVal = await scwin.f_gridValidate();

    if( rowIndex == null ) return;

	//DetailкЈЄл¶ђлУЬмЧР  validate м≤інБђ   
	if( !chkVal ) {
		//мИШм†Хм§СмЭЄ нПђмЭЄнД∞л°Ь мЭілПЩнХЬлЛ§.
		for( var idx=0; idx < ds_oilStation.getRowCount(); idx++) {
			if( ds_oilStation.getCellData(idx, "clntNo")==ds_dcUPrice.getCellData(0, "clntNo") ) {
                gr_oilStation.setFocusedCell(idx, 1, false);
				break;
			}
		}

		// if( rowIndex == ds_oilStation.getRowPosition() ) {
        if( scwin.updateStaus != "" ) {
			await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ['[мИШм†ХмВђнХ≠ мЧђлґА]']); //"@мЭД(л•Љ) нЩХмЭЄнХШмЧђ м£ЉмЛ≠мЛЬмШ§.";
			/*
			if(updateStaus=="1"){
				$c.gus.cfAlertMsg(MSG_CM_ERR_041, [ 'лЛ®к∞АмЧР 0','мЮЕл†•']); //"@мЭА(лКФ) @нХ† мИШ мЧЖмКµлЛИлЛ§.";
			}					
			if(updateStaus=="2"){
				$c.gus.cfAlertMsg(MSG_CM_ERR_018, ['[кЄ∞м§АмЭЉмЮРмЭШ нХілЛє мЫФ]']); //"@мЭА(лКФ) мЬ†нЪ®нХЬ лВ†мІЬк∞А мХДлЛЩлЛИлЛ§."
			}							
			if(updateStaus=="3"){
				$c.gus.cfAlertMsg(MSG_CM_ERR_041, [ 'кЄ∞м§АмЭЉмЮРмЭШ нХілЛє мЫФмЧР лМАнХЬ лІИк∞РмЧђлґАк∞А [лІИк∞Рм§С]лШРлКФ [лІИк∞РмЩДл£М]мЭЄ к≤љмЪ∞','м†АмЮ•']);
			}
			*/
		}

		return;
	} else {
        var f_dcPrice = ds_oilStation.getCellData(rowIndex,"clntNo"); 
        ds_dcUPrice.clearFilter();
        ds_dcUPrice.setColumnFilter( 
                            {type: 'row', 
                            colIndex:'clntNo', 
                            key: f_dcPrice, 
                            condition: 'and', 
                            exactMatch:true}
                        );
		scwin.f_GridTitleChange(rowIndex);	    
	}
    totalRows1.setValue(ds_dcUPrice.getAllFilteredJSON().length);
    scwin.updateStaus = "";

    await scwin.f_jobCloseYnSet();


    /* for( var i=0; i < ds_dcUPrice.getTotalRow(); i++ ) {
        let fIdx = ds_dcUPrice.getFilteredRowIndex(i);
        if( fIdx >= 0 ) {
            if( scwin.addRow == "true" ) {
                pCloseYM= scwin.fromDate_YMD;
            } else {
                pCloseYM= ds_dcUPrice.getCellData(fIdx, "stdDt");	// кЄ∞м§АмЭЉмЮР
            }
            pCloseYM = pCloseYM.substring(0,6);
            pMgntNo	= ds_dcUPrice.getCellData(fIdx, "clntNo");    // к±∞лЮШм≤Ш


            console.log("=======[1]ds_oilStation_onrowpositionchange==pMgntNo:"+pMgntNo+", pCloseYM:"+pCloseYM+", fIdx:"+fIdx);
            //cfJobCloseYN(лІИк∞РмЪФм≤≠кµђлґД, лІИк∞РлЕДмЫФ, лІИк∞РмЭЉ, мЮСмЧЕл≤ИнШЄ, кіАл¶ђл≤ИнШЄ, л¶ђнДікµђлґД, мЮСмЧЕлІИк∞Р+мД†нЦЙлІИк∞Рм≤інБђ кµђлґД, нЪМмВђмљФлУЬ);
             let isCloseYN = await udc_closeYn.cfJobCloseYN("CUR", pCloseYM, "00", "TR25",  pMgntNo, "DAY", "", "");
                console.log("=======[2]ds_oilStation_onrowpositionchange==isCloseYN:"+isCloseYN+", pCloseYM:"+pCloseYM);

            if( (isCloseYN == "1") || (isCloseYN == "DNF") ) {
                gr_dcUPrice.setCellReadOnly(fIdx, "upr", false);  // f_EditTrue
            } else {
                gr_dcUPrice.setCellReadOnly(fIdx, "upr", true);   // f_EditNone
            }
        }
    } */

    gr_dcUPrice.setFocusedCell(0, "stdDt", false);
};

scwin.f_jobCloseYnSet = async function() {
    for( var i=0; i < ds_dcUPrice.getAllFilteredJSON().length; i++ ) {
        let fIdx = ds_dcUPrice.getFilteredRowIndex(i);
        if( fIdx >= 0 ) {

            let vCloseYM= ds_dcUPrice.getCellData(fIdx, "stdDt");	// кЄ∞м§АмЭЉмЮР
            let pCloseYM = vCloseYM.substring(0,6);
            let pMgntNo	= ds_dcUPrice.getCellData(fIdx, "clntNo");    // к±∞лЮШм≤Ш

            console.log("=======[1]ds_oilStation_onrowpositionchange==pMgntNo:"+pMgntNo+", pCloseYM:"+pCloseYM+", fIdx:"+fIdx);
            // cfJobCloseYN(лІИк∞РмЪФм≤≠кµђлґД, лІИк∞РлЕДмЫФ, лІИк∞РмЭЉ, мЮСмЧЕл≤ИнШЄ, кіАл¶ђл≤ИнШЄ, л¶ђнДікµђлґД, мЮСмЧЕлІИк∞Р+мД†нЦЙлІИк∞Рм≤інБђ кµђлґД, нЪМмВђмљФлУЬ);
            let isCloseYN = await udc_closeYn.cfJobCloseYN("CUR", pCloseYM, "00", "TR25",  pMgntNo, "", "N", "");
            console.log("=======[2]ds_oilStation_onrowpositionchange==isCloseYN:"+isCloseYN+", pCloseYM:"+pCloseYM);

            if( (isCloseYN == "1") || (isCloseYN == "DNF") ) {
                gr_dcUPrice.setCellReadOnly(fIdx, "upr", false);  // f_EditTrue
            } else {
                gr_dcUPrice.setCellReadOnly(fIdx, "upr", true);   // f_EditNone
            }
        }
    }
};

scwin.gr_oilStation_oncellclick = function (rowIndex, columnIndex, columnId) {
    if( scwin.updateStaus == "" ) {
        // gr_dcUPrice.removeFocusedCell();
    }
};

//-------------------------------------------------------------------------
// DetailкЈЄл¶ђлУЬмЧР  Titleл™Е Setting(л≥ікіАм£ЉмЬ†мЖМ-мИШмИШл£МлЛ®к∞А & мІБлІ§м£ЉмЬ†мЖМ-нХ†мЭЄлЛ®к∞А)
//-------------------------------------------------------------------------
scwin.f_GridTitleChange = function (row) {
	var oilStatClsCd = ds_oilStation.getCellData(row, "oilStatClsCd");

	if(oilStatClsCd=="02"){ //м£ЉмЬ†мЖМкµђлґД : 02(л≥ікіАм£ЉмЬ†мЖМ)
        price.setValue("мИШмИШл£МлЛ®к∞А");
	}
	if(oilStatClsCd=="03"){ //м£ЉмЬ†мЖМкµђлґД : 03(мІБлІ§м£ЉмЬ†мЖМ)
        price.setValue("нХ†мЭЄлЛ®к∞А");
	}
};

scwin.ds_dcUPrice_ondataload = async function () {
    let rowCnt = ds_dcUPrice.getTotalRow();


	if( rowCnt == 0 ) {
	    if( $c.gus.cfCheckCreateFlag() == true){
	    	$c.gus.cfTurnCreateFlag(false);
	    }else{
	 		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
	    }
       return;
	} 

    if (rowCnt > 0) {
        var f_dcPrice = ds_oilStation.getCellData(0,"clntNo"); 
        ds_dcUPrice.clearFilter();
        ds_dcUPrice.setColumnFilter( 
                            {type: 'row', 
                            colIndex:'clntNo', 
                            key: f_dcPrice, 
                            condition: 'and', 
                            exactMatch:true}
                        );        
        ds_dcUPrice.multisort(scwin.sort_options1);
    }  
};

scwin.btn_Search_onclick = function (e) {
    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// м°∞нЪМ
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
	var oilStatDivision = "";
	if( lc_oilStatDivision.getValue()=="02" ){ //л≥ікіАм£ЉмЬ†мЖМ
		oilStatDivision = "01"; //л≥ікіА
	}
	if( lc_oilStatDivision.getValue()=="03" ){ //мІБлІ§м£ЉмЬ†мЖМ
		oilStatDivision = "02"; //мІБлІ§
	}

    dma_search.set("oilStatDivision",oilStatDivision );
    dma_search.set("oilStation",lc_oilStation.getValue());

    $c.sbm.execute(sbm_master);
};

scwin.sbm_master_submitdone = function (e) {
    if( scwin.pos_rowSts >= 0 ) {
        gr_oilStation.setFocusedCell(scwin.pos_rowSts, "clntNo", false);
        if( lc_oilStation.getValue() != "" ) {
            // gr_dcUPrice.setFocusedCell(scwin.pos_rowSts, "stdDt", false);
        }
    }
};

//-------------------------------------------------------------------------
// мИШмИШл£М/нХ†мЭЄлЛ®к∞А Grid  : нЦЙмґФк∞А
//-------------------------------------------------------------------------
scwin.f_CostAddRow = async function () {	
    let m_row = ds_oilStation.getRowPosition(); 
    let vIdx = ds_dcUPrice.getRowCount();    

    if( m_row == null ) return;
	if( ds_oilStation.getCellData(ds_oilStation.getRowPosition(), "clntNo")=="" ) {
		$c.gus.cfAlertMsg(MSG_CM_ERR_002,"[м£ЉмЬ†мЖМмљФлУЬ]");	//нХДмИШ мЮЕл†• нХ≠л™©мЮЕлЛИлЛ§.		
		return;
	}

	if( ds_oilStation.getRowCount() != 0 ) {        
	    let iRow = ds_dcUPrice.insertRow(vIdx); 
        // console.log("=========iRow:"+iRow+", vIdx:"+vIdx);

        let oilStatClsCd = ds_oilStation.getCellData(m_row, "oilStatClsCd");
        if( oilStatClsCd == "02" ) {    // л≥ікіАм£ЉмЬ†мЖМ
            ds_dcUPrice.setCellData(vIdx, "uprClsCd", "01");    // л≥ікіА
        }
        if( oilStatClsCd == "03" ) {    // мІБлІ§м£ЉмЬ†мЖМ
            ds_dcUPrice.setCellData(vIdx, "uprClsCd", "02");    // мІБлІ§
        }
        ds_dcUPrice.setCellData(vIdx, "clntNo", ds_oilStation.getCellData(m_row, "clntNo"));
        gr_dcUPrice.setFocusedCell(vIdx, "upr", false);

        scwin.addRow = "true";
		var yyyymmdd = scwin.fromDate_YMD;

		var isCloseYN = await scwin.f_JobCloseYN(); 
        // console.log("===========isCloseYN:"+isCloseYN);
		if( ( isCloseYN == "0" ) ||  (isCloseYN == "2" ) ) { //(лІИк∞Рм§С, лІИк∞РмЩДл£МмЭЄ к≤љмЪ∞) Edit лґИк∞АлК•
			if( yyyymmdd.substring(4,6)>="12" ) {
				ds_dcUPrice.setCellData(vIdx, "stdDt", Number(yyyymmdd.substring(0,4))+1);
			}else {
				ds_dcUPrice.setCellData(vIdx, "stdDt", yyyymmdd.substring(0,4));
			}

			ds_dcUPrice.setCellData(vIdx, "closeClsCd",  "");
			scwin.addRow = "false";
			return false;
		}else {
			ds_dcUPrice.setCellData(vIdx, "stdDt", yyyymmdd);
			scwin.addRow = "false";
		}      

        gr_dcUPrice.setCellReadOnly(iRow, "stdDt", false);
        gr_dcUPrice.setCellReadOnly(iRow, "upr", false);
	} 
};

//-------------------------------------------------------------------------
// мИШмИШл£М/нХ†мЭЄлЛ®к∞А Grid : нЦЙмВ≠м†Ь
//-------------------------------------------------------------------------
scwin.f_DelRow = async function () {
    let vRowPos = ds_dcUPrice.getRowPosition();
    let chkRowStatus = ds_dcUPrice.getRowStatus(vRowPos);
    var isCloseYN = await scwin.f_JobCloseYN();

	if( ( isCloseYN == "1" ) || ( isCloseYN == "DNF" ) ) {//edit к∞АлК•
         // нЦЙмґФк∞А(мВљмЮЕ)мЭЄ к≤љмЪ∞ мВ≠м†Ь
        if( chkRowStatus == "C" ) {
            ds_dcUPrice.removeRow(vRowPos);
        } else {
            ds_dcUPrice.deleteRow(vRowPos);
            gr_dcUPrice.setFocusedCell(vRowPos, "upr", false);
        }
	} else if( isCloseYN == "0" ) { //isCloseYN:0(лІИк∞Рм§С) --> edit лґИк∞АлК•
		$c.gus.cfAlertMsg(MSG_CM_ERR_041, [ 'кЄ∞м§АмЭЉмЮРмЭШ нХілЛє мЫФмЧР лМАнХЬ лІИк∞РмЧђлґАк∞А [лІИк∞Рм§С]лШРлКФ [лІИк∞РмЩДл£М]мЭЄ к≤љмЪ∞','мВ≠м†Ь']);  
		return false;
	 }else if( isCloseYN == "2" ) { //isCloseYN:2(лІИк∞РмЩДл£М) --> edit лґИк∞АлК•
		$c.gus.cfAlertMsg(MSG_CM_ERR_041, [ 'кЄ∞м§АмЭЉмЮРмЭШ нХілЛє мЫФмЧР лМАнХЬ лІИк∞РмЧђлґАк∞А [лІИк∞Рм§С]лШРлКФ [лІИк∞РмЩДл£М]мЭЄ к≤љмЪ∞','мВ≠м†Ь']);  
		return false; 
	}
};

scwin.btn_Save_onclick = function (e) {
    scwin.f_Save();
};

//-------------------------------------------------------------------------
// м†АмЮ•
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
	//л≥Ак≤љнХЬ лН∞мЭінД∞к∞А мЮИлКФмІА м≤інБђнХЬлЛ§.(к∞Б dataSet л≥Ак≤љк≤АмВђ)
    if(ds_dcUPrice.getModifiedIndex().length == 0) {
	    $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["мИШмИШл£М/нХ†мЭЄлЛ®к∞А кЈЄл¶ђлУЬ"] );	//л≥Ак≤љлРЬ м†Хл≥ік∞А мЧЖмКµлЛИлЛ§.
	    return;
    }
    if(ds_dcUPrice.getCellData(ds_dcUPrice.getRowPosition(),"clntNo")==""){
		$c.gus.cfAlertMsg(MSG_CM_ERR_002,"[м£ЉмЬ†мЖМ мљФлУЬ]");	//нХДмИШ мЮЕл†• нХ≠л™©мЮЕлЛИлЛ§.
      return false;
    }

    if( !await $c.gus.cfValidate(gr_oilStation, null, true) ) return;
    if( !await $c.gus.cfValidate(gr_dcUPrice, null, true) ) return;


	//----- Add.2006.02.21 RowStatusк∞А insertмЭЄ "м£ЉмЬ†мЖМ к±∞лЮШм≤Шл≥Д" лІИк∞РмЧђлґА м≤інБђ(м†АмЮ•к∞АлК•мЧђлґА return)
	if( !await scwin.f_chkJobCloseYN() ) {
		$c.gus.cfAlertMsg(MSG_CM_ERR_041, [ "кЄ∞м§АмЭЉмЮРмЭШ нХілЛє мЫФмЧР лМАнХЬ лІИк∞РмЧђлґАк∞А [лІИк∞Рм§С]лШРлКФ [лІИк∞РмЩДл£М]мЭЄ к≤љмЪ∞','м†АмЮ•"]);  
		return false;
	}

    let confirm = await $c.win.confirm(MSG_CM_CRM_001); //м†АмЮ•нХШмЛЬк≤†мКµлЛИкєМ?
   	if (confirm) {
        $c.sbm.execute(sbm_save);
   	}
};

scwin.sbm_save_submitdone = async function (e) {    
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        scwin.pos_rowSts = ds_oilStation.getRowPosition(); //м†АмЮ•нХШкЄ∞ м†ДмЧР, мї§мДЬк∞А мЮИлНШ rowмЬДмєШл•Љ л≥АмИШмЧР лЛімХДлЖУкЄ∞
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// мД±к≥µм†БмЬЉл°Ь м†АмЮ•нХШмШАмКµлЛИлЛ§
        // scwin.f_Retrieve();
        scwin.btn_Search_onclick();
    }
};

//-------------------------------------------------------------------------
// RowStatusк∞А insertмЭЄ "м£ЉмЬ†мЖМ к±∞лЮШм≤Шл≥Д" лІИк∞РмЧђлґА м≤інБђ
//-------------------------------------------------------------------------
scwin.f_chkJobCloseYN = async function (){
	var pReqKind 	= "CUR";	// лІИк∞РмЪФм≤≠кµђлґД
	var pCloseYM 	= "";		// лІИк∞РлЕДмЫФ	---------------> "кЄ∞м§АмЭЉмЮР" лД£мЦім§М
	var pCloseDD 	= "00";		// лІИк∞РмЭЉ
	var pWorkNo 	= "TR25";	// мЮСмЧЕл≤ИнШЄ    
	var pMgntNo		= "";		// кіАл¶ђл≤ИнШЄ    	---------------> "м£ЉмЬ†мЖМл≥Д к±∞лЮШм≤Ш" к±∞лЮШм≤Ш
	var pRtnKind 	= "";		// л¶ђнДікµђлґД
	var pDualChkYN 	= "";		// мЮСмЧЕлІИк∞Р+мД†нЦЙлІИк∞Рм≤інБђ кµђлґД
	var isCloseYN	= "";		// лІИк∞РкµђлґДмљФлУЬ	
	var editNoneCnt = 0;


	//FilteringлРЬ  rowк∞ѓмИШ лІМнБЉ,, л£®нФДлПМл¶ђкЄ∞
	for( let j=0; j < ds_dcUPrice.getRowCount(); j++ ) {	
		if(ds_dcUPrice.getRowStatus(j) == "C") {	// as-is мГБнГЬк∞Т(0: Normal, 1: Insert, 2: Update, 3: Delete)
			pCloseYM= ds_dcUPrice.getCellData(j, "stdDt" );	//кЄ∞м§АмЭЉмЮР
			pMgntNo	= ds_dcUPrice.getCellData(j, "clntNo" );//к±∞лЮШм≤Ш

            isCloseYN = await udc_closeYn.cfJobCloseYN(pReqKind,pCloseYM.substring(0,6),pCloseDD,pWorkNo,pMgntNo,pRtnKind,pDualChkYN);
			ds_dcUPrice.setCellData( j,  "closeClsCd" , isCloseYN);

			//editлґИк∞АлК• нХ† к≤љмЪ∞, cntл•Љ 1мФ© м¶Эк∞А нХЬлЛ§. "cnt>0"мЭіл©і м†АмЮ•лґИк∞АлК•.
			if( (isCloseYN != "1") && (isCloseYN != "DNF") ){
				editNoneCnt += 1;
			}
		}
	}

	if(editNoneCnt>0){	//"cnt>0"мЭіл©і м†АмЮ•лґИк∞АлК•.
		return false;
	}else {				//"cnt==0"мЭіл©і м†АмЮ•к∞АлК•.
		return true;
	}
};

//-------------------------------------------------------------------------
// "м£ЉмЬ†мЖМ к±∞лЮШм≤Шл≥Д" лІИк∞РмЧђлґА м≤інБђ (Add.2006.02.22)
//-------------------------------------------------------------------------
scwin.f_JobCloseYN = async function () {
	var pReqKind 	= "CUR";	// лІИк∞РмЪФм≤≠кµђлґД
	var pCloseYM 	= "";		// лІИк∞РлЕДмЫФ	---------------> "кЄ∞м§АмЭЉмЮР" лД£мЦім§М
	var pCloseDD 	= "00";		// лІИк∞РмЭЉ
	var pWorkNo 	= "TR25";	// мЮСмЧЕл≤ИнШЄ    
	var pMgntNo		= "";		// кіАл¶ђл≤ИнШЄ    	---------------> "м£ЉмЬ†мЖМл≥Д к±∞лЮШм≤Ш" к±∞лЮШм≤Ш
	var pRtnKind 	= "";		// л¶ђнДікµђлґД
	var pDualChkYN 	= "";		// мЮСмЧЕлІИк∞Р+мД†нЦЙлІИк∞Рм≤інБђ кµђлґД
	// var isCloseYN	= "";		// лІИк∞РкµђлґДмљФлУЬ	


	if( scwin.addRow == "true" ) {
		pCloseYM= scwin.fromDate_YMD;
	} else {
		pCloseYM= ds_dcUPrice.getCellData( ds_dcUPrice.getRowPosition(),  "stdDt" );	// кЄ∞м§АмЭЉмЮР
	}
	pMgntNo	= ds_dcUPrice.getCellData( ds_dcUPrice.getRowPosition(),  "clntNo" );		// к±∞лЮШм≤Ш

    //cfJobCloseYN(лІИк∞РмЪФм≤≠кµђлґД,лІИк∞РлЕДмЫФ,лІИк∞РмЭЉ,мЮСмЧЕл≤ИнШЄ,кіАл¶ђл≤ИнШЄ,л¶ђнДікµђлґД);    
    /**
     * @param  : pReqKind  : лІИк∞РмЪФм≤≠кµђлґД("PRE":мД†нЦЙлІИк∞Рм≤інБђ, "CUR":мЮСмЧЕлІИк∞Рм≤інБђ)
     *           pCloseYM  : лІИк∞РлЕДмЫФ(YYYYMM, MMмЭі '00'мЭі лУ§мЦік∞АлКФ к≤љмЪ∞лКФ лЕД,мЫФ лІИк∞РмЭЉк≤љмЪ∞)
     *           pCloseDD  : лІИк∞РмЭЉ | лІИк∞Рм£ЉкЄ∞ (Y)лЕДлІИк∞Р   : 00
     *                                     (H)л∞ШкЄ∞лІИк∞Р : 1:м†ДкЄ∞, 2:нЫДкЄ∞
     *                                     (Q)лґДкЄ∞лІИк∞Р : 1,2,3,4
     *                                     (M)мЫФлІИк∞Р   : 00
     *                                     (W)м£ЉлІИк∞Р   : 1,2,3,4,5
     *                                     (D)мЭЉлІИк∞Р   : нХілЛємЭЉ(01~31)
     *           pWorkNo   : мЮСмЧЕл≤ИнШЄ
     *           pMgntNo   : кіАл¶ђл≤ИнШЄ(Default : "0")
     *           pRtnKind  : DAY:лІИк∞РмЭЉл¶ђнДі, ARR:к≤∞к≥Љл•Љл∞∞мЧіл°Ь, null:лІИк∞РмЧђлґА к≤∞к≥Љл¶ђнДі
     *           pDualChkYN: мЮСмЧЕлІИк∞Рм≤інБђкЄ∞(CUR) мД†нЦЙлІИк∞РкєМмІА м≤інБђл•Љ нХ†к≤ГмЭЄк∞А мЧђлґА Y:м≤інБђнХ®
     *           pCoCd     : нЪМмВђмљФлУЬ
     *
     * @return : 0     : лІИк∞Рм§С
     *           1     : лѓЄлІИк∞Р
     *           2     : лІИк∞РмЩДл£М
     *           DNF   : Data Not Found
     *           null  : нММлЭЉл©ФнД∞ мШ§л•Ш
     *           лІИк∞РмЭЉ : л¶ђнДікµђлґДмЭі "DAY" мЭЉк≤љмЪ∞(YYYYMMDD)
     *           ArrayObj : л¶ђнДікµђлґДмЭі "ARR" мЭЉк≤љмЪ∞ (л¶ђнДімљФлУЬ,мЮСмЧЕл≤ИнШЄ,мЮСмЧЕл™Е,CUR or PRE)
     *           л¶ђнДікµђлґДмЭі DAY,ARRмЭі мХДлЛМк≤љмЪ∞ мД†нЦЙлІИк∞РмЭі мХИлРЬк≤љмЪ∞ (P0:лІИк∞Рм§С,P1:лѓЄлІИк∞Р л¶ђнДінХ®)
     */
    let isCloseYN = await udc_closeYn.cfJobCloseYN(pReqKind,pCloseYM.substring(0,6),pCloseDD,pWorkNo,pMgntNo,pRtnKind,pDualChkYN);
	return isCloseYN;
};

