	if( Colid=="stdDt" ) {	
		if( Row > 0 ) {
			if( ds_dcUPrice.getRowStatus(ds_dcUPrice.getRowposition()) == "C"){ //SysStatus-----мГБнГЬк∞Т(0: Normal, 1: Insert, 2: Update, 3: Delete)
				scwin.f_EditTrue();
			} else {
				scwin.f_EditNone();
			}
		}
	}	

	if( Colid=="upr" ) {
		if( Row > 0 ) {
			if( ds_dcUPrice.getRowStatus(ds_dcUPrice.getRowposition()) == "C"){ //SysStatus----- мГБнГЬк∞Т(0: Normal, 1: Insert, 2: Update, 3: Delete)
				gr_dcUPrice.setColumnDisabled("uPr", false);
			} else {
