// MasterкЈЄл¶ђлУЬ(ds_oilStation) OnRowPosChanged(row)мЛЬмЧР, DetailкЈЄл¶ђлУЬмЧР  validate м≤інБђ
//-----------------------------------------------------------------------------------
scwin.f_gridValidate = function () { 
	var stdDt		= ""; //кЄ∞м§АмЭЉмЮР
	var rowStatus	= ""; //RowStatus
	var isCloseYN	= ""; //лІИк∞РмЧђлґА

	for( let j=0; j<ds_dcUPrice.getRowCount(); j++ ) {//rowк∞ѓмИШ лІМнБЉ,, л£®нФДлПМл¶ђкЄ∞
		rowStatus = ds_dcUPrice.getRowStatus(j);	
		//if( rowStatus==1 || rowStatus==3 ){//RowStatus:1(Insert), 3(Update)
        if( rowStatus=="C" || rowStatus=="U" ){//RowStatus:1(Insert), 3(Update)

			//2.кЄ∞м§АмЭЉмЮР Validate м≤інБђ
			stdDt = ds_dcUPrice.getCellData(j, "stdDt");
            if ( !$c.date.isDate(stdDt) || stdDt.length < 8 ) {
				// ds_dcUPrice.setCellData(j, "stdDt", ds_dcUPrice.getOriginalCellData(j, "stdDt"));
				scwin.updateStaus = "2";
				return false;
			}	

			//3.кЄ∞м§АмЭЉмЮР лІИк∞РмЧђлґА м≤інБђ
			isCloseYN = scwin.f_JobCloseYN();
			if( (isCloseYN=="0") || (isCloseYN=="2") ) {//edit лґИк∞АлК•	
				scwin.updateStaus = "3";
				return false;
			}

			//1.лЛ®к∞А(мЫР) м≤інБђ
			if( ds_dcUPrice.getCellData(j,"upr") == 0 ) {
				// ds_dcUPrice.setCellData(j,"upr", ds_dcUPrice.getOriginalCellData(j,"upr"));
				scwin.updateStaus = "1";
				return false;
			}			
		}//end if(rowStatus)	
	}//end for 

	return true;		
};

//-------------------------------------------------------------------------
// кЄ∞м§АмЭЉмЮР customFormatter SET
//-------------------------------------------------------------------------
scwin.f_dateFormat = function (data) {
    if (data == null || data === "") {
        return "";
    }

    let strData = data.toString().trim();

    if (strData.length === 8) {
        // 8мЮРл¶ђмЭЄ к≤љмЪ∞
        let year = strData.substring(0, 4);
        let month = strData.substring(4, 6);
        let day = strData.substring(6, 8);
        return year + "/" + month + "/" + day;

    } else if (strData.length === 6) {
        // 6мЮРл¶ђмЭЄ к≤љмЪ∞
        let year = strData.substring(0, 4);
        let month = strData.substring(4, 6);
        return year + "/" + month + "/";

     } else if (strData.length === 4) {
        // 4мЮРл¶ђмЭЄ к≤љмЪ∞
        let year = strData.substring(0, 4);
        return year + "/" + "" + "/";

    } else {
        return strData;
    }
};

